!function(){"use strict";$(document).ready((function(){var t=$(".js-progress-card");if(t.length){var n=t.attr("data-url"),a=parseInt(t.attr("data-seconds"))||30,r=t.find(".progress-bar");$({width:0}).animate({width:100},{duration:1e3*a,easing:"linear",step:function(t){r.css("width","".concat(t,"%"))},complete:function(){n&&(window.location.href=n)}})}}))}(jQuery);